import httpx
from pydantic import BaseModel
from typing import Optional

class User(BaseModel):
    id: int
    name: str
    email: str

class UserServiceError(Exception):
    pass

class UserService:
    def __init__(self, base_url: str, api_key: str, timeout: float = 10.0):
        self._client = httpx.Client(
            base_url=base_url,
            headers={"Authorization": f"Bearer {api_key}",
                     "Accept": "application/json"},
            timeout=timeout,
        )

    def get_user(self, user_id: int) -> User:
        try:
            response = self._client.get(f"/users/{user_id}")
            response.raise_for_status()
            return User.model_validate(response.json())
        except httpx.HTTPStatusError as e:
            if e.response.status_code == 404:
                raise UserServiceError(f"User {user_id} not found") from e
            raise UserServiceError(f"API error {e.response.status_code}") from e
        except httpx.TransportError as e:
            raise UserServiceError(f"Network error: {e}") from e

    def create_user(self, name: str, email: str) -> User:
        try:
            response = self._client.post("/users", json={"name": name, "email": email})
            response.raise_for_status()
            return User.model_validate(response.json())
        except httpx.HTTPStatusError as e:
            raise UserServiceError(f"Create failed: {e.response.status_code}") from e

    def close(self):
        self._client.close()

    def __enter__(self):
        return self

    def __exit__(self, *args):
        self.close()

# Usage
with UserService("https://api.example.com", api_key="secret") as svc:
    user = svc.get_user(42)
    print(user.name)

import asyncio
import httpx
from tenacity import retry, stop_after_attempt, wait_exponential, retry_if_exception

def is_retryable(exc: BaseException) -> bool:
    if isinstance(exc, httpx.HTTPStatusError):
        return exc.response.status_code in {429, 500, 502, 503, 504}
    return isinstance(exc, (httpx.ConnectError, httpx.TimeoutException))

class AsyncUserService:
    def __init__(self, base_url: str, api_key: str):
        self._client = httpx.AsyncClient(
            base_url=base_url,
            headers={"Authorization": f"Bearer {api_key}"},
            timeout=httpx.Timeout(connect=5.0, read=30.0, write=5.0, pool=5.0),
        )

    @retry(
        stop=stop_after_attempt(3),
        wait=wait_exponential(multiplier=1, min=1, max=10),
        retry=retry_if_exception(is_retryable),
        reraise=True,
    )
    async def get_user(self, user_id: int) -> dict:
        response = await self._client.get(f"/users/{user_id}")
        response.raise_for_status()
        return response.json()

    async def close(self):
        await self._client.aclose()

async def main():
    svc = AsyncUserService("https://api.example.com", "secret")
    try:
        user = await svc.get_user(42)
        print(user)
    finally:
        await svc.close()

import httpx, json

def call_claude(prompt: str, api_key: str) -> str:
    with httpx.Client(timeout=120) as client:
        response = client.post(
            "https://api.anthropic.com/v1/messages",
            headers={
                "x-api-key": api_key,
                "anthropic-version": "2023-06-01",
                "content-type": "application/json",
            },
            json={
                "model": "claude-3-5-sonnet-20241022",
                "max_tokens": 1024,
                "messages": [{"role": "user", "content": prompt}],
            },
        )
        response.raise_for_status()
        return response.json()["content"][0]["text"]
